import React, { useEffect, useState, useCallback } from 'react';
import { Borrow, Book, Member } from '../types';
import api from '../utils/api';

const SBG: any = { borrowed:'#fef3c7', returned:'#d1fae5', overdue:'#fee2e2', lost:'#ede9fe' };
const SBC: any = { borrowed:'#d97706', returned:'#059669', overdue:'#dc2626', lost:'#7c3aed' };

export default function Borrows() {
  const [borrows, setBorrows] = useState<Borrow[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [sf, setSf] = useState('');
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [books, setBooks] = useState<Book[]>([]);
  const [members, setMembers] = useState<Member[]>([]);
  const [form, setForm] = useState({ book_id:'', member_id:'', due_date:'' });
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [msg, setMsg] = useState('');

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get('/borrows', { params: { status: sf, page, limit:10 } });
      setBorrows(data.data); setTotal(data.total);
    } finally { setLoading(false); }
  }, [sf, page]);

  useEffect(() => { load(); }, [load]);

  const openModal = async () => {
    const [b, m] = await Promise.all([api.get('/books', { params:{ limit:100 } }), api.get('/members', { params:{ limit:100 } })]);
    setBooks(b.data.data.filter((bk: Book) => bk.available_copies > 0));
    setMembers(m.data.data.filter((mb: Member) => mb.status === 'active'));
    const d = new Date(); d.setDate(d.getDate()+14);
    setForm({ book_id:'', member_id:'', due_date:d.toISOString().split('T')[0] });
    setError(''); setModal(true);
  };

  const saveBorrow = async () => {
    if (!form.book_id || !form.member_id || !form.due_date) { setError('All fields required!'); return; }
    setSaving(true); setError('');
    try {
      await api.post('/borrows', { book_id: Number(form.book_id), member_id: Number(form.member_id), due_date: form.due_date });
      setModal(false); load();
    } catch (e: any) { setError(e.response?.data?.message || 'Error'); }
    finally { setSaving(false); }
  };

  const returnBook = async (id: number) => {
    if (!window.confirm('Mark as returned?')) return;
    const { data } = await api.put(`/borrows/${id}/return`);
    if (data.fine > 0) setMsg(`Returned! Fine: $${data.fine} (${data.overdueDays} days overdue)`);
    else setMsg('Book returned successfully! ✓');
    setTimeout(() => setMsg(''), 4000);
    load();
  };

  const inp: React.CSSProperties = { width:'100%', padding:'9px 12px', border:'2px solid #e8e0d0', borderRadius:9, fontSize:13, fontFamily:'inherit', outline:'none', color:'#1a1a2e' };
  const filters = ['', 'borrowed', 'returned', 'overdue'];

  return (
    <div className="page-enter" style={{ padding:32 }}>
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:24 }}>
        <div>
          <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:28, fontWeight:700 }}>Borrows</h1>
          <p style={{ color:'#9ca3af', fontSize:13, marginTop:4 }}>{total} borrow records</p>
        </div>
        <button onClick={openModal} style={{ padding:'9px 20px', background:'#1a1a2e', color:'#fff', border:'none', borderRadius:10, fontSize:13, fontWeight:600, cursor:'pointer', fontFamily:'inherit' }}>+ Issue Book</button>
      </div>

      {msg && <div style={{ background:'#d1fae5', color:'#059669', padding:'12px 16px', borderRadius:10, fontSize:13, fontWeight:600, marginBottom:16 }}>{msg}</div>}

      <div style={{ display:'flex', gap:8, marginBottom:20, flexWrap:'wrap' }}>
        {filters.map(f => (
          <button key={f||'all'} onClick={() => { setSf(f); setPage(1); }}
            style={{ padding:'8px 18px', background: sf===f ? '#1a1a2e' : '#fff', color: sf===f ? '#fff' : '#6b7280', border: sf===f ? 'none' : '1px solid #e8e0d0', borderRadius:10, fontSize:13, fontWeight:500, cursor:'pointer', fontFamily:'inherit', textTransform:'capitalize' }}>
            {f || 'All'}
          </button>
        ))}
      </div>

      <div style={{ background:'#fff', border:'1px solid #e8e0d0', borderRadius:16, overflow:'hidden' }}>
        <table style={{ width:'100%', borderCollapse:'collapse' }}>
          <thead>
            <tr style={{ background:'#f5f0e8' }}>
              {['Book','Member','Borrow Date','Due Date','Status','Fine','Actions'].map(h => (
                <th key={h} style={{ padding:'11px 16px', textAlign:'left', fontSize:11, fontWeight:700, color:'#6b7280', textTransform:'uppercase', letterSpacing:'.05em' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr><td colSpan={7} style={{ textAlign:'center', padding:60, color:'#9ca3af' }}>Loading...</td></tr>
            ) : borrows.length ? borrows.map((b, i) => (
              <tr key={b.id} style={{ borderTop: i>0 ? '1px solid #f5f0e8' : 'none' }}>
                <td style={{ padding:'13px 16px' }}>
                  <div style={{ fontSize:13, fontWeight:600 }}>{b.title}</div>
                  <div style={{ fontSize:11, color:'#9ca3af' }}>{b.author}</div>
                </td>
                <td style={{ padding:'13px 16px' }}>
                  <div style={{ fontSize:13 }}>{b.member_name}</div>
                  <div style={{ fontSize:11, fontFamily:'monospace', color:'#c9a84c' }}>{b.member_code}</div>
                </td>
                <td style={{ padding:'13px 16px', fontSize:13, color:'#6b7280' }}>{b.borrow_date?.split('T')[0]}</td>
                <td style={{ padding:'13px 16px', fontSize:13, fontWeight: b.status==='overdue'?700:400, color: b.status==='overdue'?'#dc2626':'#6b7280' }}>{b.due_date?.split('T')[0]}</td>
                <td style={{ padding:'13px 16px' }}><span style={{ fontSize:11, fontWeight:600, padding:'3px 10px', borderRadius:99, background:SBG[b.status]||'#f3f4f6', color:SBC[b.status]||'#6b7280' }}>{b.status}</span></td>
                <td style={{ padding:'13px 16px', fontWeight:700, color: b.fine_amount>0?'#dc2626':'#9ca3af' }}>{b.fine_amount>0?`$${Number(b.fine_amount).toFixed(2)}`:'—'}</td>
                <td style={{ padding:'13px 16px' }}>
                  {(b.status==='borrowed'||b.status==='overdue') ? (
                    <button onClick={() => returnBook(b.id)} style={{ padding:'5px 12px', background:'#d1fae5', color:'#059669', border:'none', borderRadius:7, fontSize:12, cursor:'pointer', fontWeight:600 }}>Return</button>
                  ) : <span style={{ color:'#d1d5db', fontSize:12 }}>—</span>}
                </td>
              </tr>
            )) : <tr><td colSpan={7} style={{ textAlign:'center', padding:60, color:'#9ca3af' }}>📋 No borrows found</td></tr>}
          </tbody>
        </table>
      </div>

      {Math.ceil(total/10) > 1 && (
        <div style={{ display:'flex', alignItems:'center', justifyContent:'center', gap:8, marginTop:20 }}>
          <button onClick={() => setPage(p=>Math.max(1,p-1))} disabled={page===1} style={{ padding:'7px 16px', background:'#e8e0d0', border:'none', borderRadius:8, cursor:'pointer', opacity:page===1?0.4:1 }}>← Prev</button>
          <span style={{ fontSize:13, color:'#6b7280' }}>Page {page} of {Math.ceil(total/10)}</span>
          <button onClick={() => setPage(p=>Math.min(Math.ceil(total/10),p+1))} disabled={page===Math.ceil(total/10)} style={{ padding:'7px 16px', background:'#e8e0d0', border:'none', borderRadius:8, cursor:'pointer', opacity:page===Math.ceil(total/10)?0.4:1 }}>Next →</button>
        </div>
      )}

      {modal && (
        <div style={{ position:'fixed', inset:0, background:'rgba(26,26,46,0.5)', backdropFilter:'blur(4px)', zIndex:1000, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
          <div style={{ background:'#fff', borderRadius:20, padding:28, width:'100%', maxWidth:420 }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:22 }}>
              <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:20, fontWeight:700 }}>Issue Book</h2>
              <button onClick={() => setModal(false)} style={{ background:'#f5f0e8', border:'none', width:32, height:32, borderRadius:8, cursor:'pointer', fontSize:16 }}>✕</button>
            </div>
            {error && <div style={{ background:'#fee2e2', color:'#dc2626', padding:'10px 14px', borderRadius:9, fontSize:13, marginBottom:14 }}>{error}</div>}
            <div style={{ display:'grid', gap:14 }}>
              <div><label style={{ display:'block', fontSize:12, fontWeight:600, color:'#6b7280', marginBottom:6 }}>Book (available only) *</label>
                <select style={inp} value={form.book_id} onChange={e=>setForm(f=>({...f,book_id:e.target.value}))}>
                  <option value="">Choose book...</option>
                  {books.map(b=><option key={b.id} value={b.id}>{b.title} ({b.available_copies} left)</option>)}
                </select>
              </div>
              <div><label style={{ display:'block', fontSize:12, fontWeight:600, color:'#6b7280', marginBottom:6 }}>Member (active only) *</label>
                <select style={inp} value={form.member_id} onChange={e=>setForm(f=>({...f,member_id:e.target.value}))}>
                  <option value="">Choose member...</option>
                  {members.map(m=><option key={m.id} value={m.id}>{m.name} ({m.member_id})</option>)}
                </select>
              </div>
              <div><label style={{ display:'block', fontSize:12, fontWeight:600, color:'#6b7280', marginBottom:6 }}>Due Date *</label>
                <input style={inp} type="date" value={form.due_date} onChange={e=>setForm(f=>({...f,due_date:e.target.value}))} />
              </div>
            </div>
            <div style={{ display:'flex', gap:10, marginTop:20 }}>
              <button onClick={() => setModal(false)} style={{ flex:1, padding:'10px', background:'#f5f0e8', border:'none', borderRadius:10, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>Cancel</button>
              <button onClick={saveBorrow} disabled={saving} style={{ flex:1, padding:'10px', background:'#1a1a2e', color:'#fff', border:'none', borderRadius:10, cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:600 }}>{saving?'Issuing...':'Issue Book'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
